#include <stdio.h>
#include <string.h>

int countWords(char *str) {
    int count = 0;
    bool inWord = false;
    while (*str) {
        if (*str == ' ' || *str == '\n' || *str == '\t') {
            inWord = false;
        } else if (!inWord) {
            inWord = true;
            count++;
        }
        str++;
    }
    return count;
}

int main() {
    char text[] = "Hello world from C!";
    printf("Words: %d\n", countWords(text));
    return 0;
}

